class ConcurrencyError(Exception):
    pass


class EventStore:
    """In-memory event store with per-aggregate versioning and subscriptions."""

    def __init__(self) -> None:
        self._events: Dict[str, List[Event]] = defaultdict(list)
        self._snapshots: Dict[str, tuple[int, dict]] = {}
        self._subscribers: List[Callable[[Event], None]] = []
        self._lock = threading.Lock()

    def append(self, events: List[Event], expected_version: int) -> None:
        if not events:
            return
        aid = events[0].aggregate_id
        with self._lock:
            current = len(self._events[aid])
            if current != expected_version:
                raise ConcurrencyError(
                    f"Expected version {expected_version}, got {current}"
                )
            for i, e in enumerate(events, start=1):
                e.version = current + i
                self._events[aid].append(e)
            # Notify subscribers outside the append order guarantee,
            # but we still call them in order here.
            to_publish = list(events)
        for e in to_publish:
            self._publish(e)

    def read_stream(self, aggregate_id: str, from_version: int = 0) -> List[Event]:
        with self._lock:
            return list(self._events[aggregate_id][from_version:])

    def save_snapshot(self, aggregate_id: str, version: int, state: dict) -> None:
        with self._lock:
            self._snapshots[aggregate_id] = (version, dict(state))

    def load_snapshot(self, aggregate_id: str) -> Optional[tuple[int, dict]]:
        with self._lock:
            snap = self._snapshots.get(aggregate_id)
            return (snap[0], dict(snap[1])) if snap else None

    # --- pub/sub for projections --------------------------------------------------
    def subscribe(self, handler: Callable[[Event], None]) -> None:
        self._subscribers.append(handler)

    def _publish(self, event: Event) -> None:
        for h in self._subscribers:
            h(event)


